#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int a1, a2, a3, b1, b2, b3;
        scanf("%d %d %d %d %d %d", &a1, &a2, &a3, &b1, &b2, &b3);
        int minA = a1;
        if (a2 < minA) minA = a2;
        if (a3 < minA) minA = a3;
        int scoreA = a1 + a2 + a3 - minA;
        int minB = b1;
        if (b2 < minB) minB = b2;
        if (b3 < minB) minB = b3;
        int scoreB = b1 + b2 + b3 - minB;
        if (scoreA > scoreB) printf("Alice\n");
        else if (scoreB > scoreA) printf("Bob\n");
        else printf("Tie\n");
    }
    return 0;
}

