import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; t++) {
            st = new StringTokenizer(br.readLine());
            int a1 = Integer.parseInt(st.nextToken());
            int a2 = Integer.parseInt(st.nextToken());
            int a3 = Integer.parseInt(st.nextToken());
            int b1 = Integer.parseInt(st.nextToken());
            int b2 = Integer.parseInt(st.nextToken());
            int b3 = Integer.parseInt(st.nextToken());
            int scoreA = a1 + a2 + a3 - Math.min(a1, Math.min(a2, a3));
            int scoreB = b1 + b2 + b3 - Math.min(b1, Math.min(b2, b3));
            if (scoreA > scoreB) sb.append("Alice\n");
            else if (scoreB > scoreA) sb.append("Bob\n");
            else sb.append("Tie\n");
        }
        System.out.print(sb.toString());
    }
}

