#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        a1 = int(next(it)); a2 = int(next(it)); a3 = int(next(it))
        b1 = int(next(it)); b2 = int(next(it)); b3 = int(next(it))
        scoreA = a1 + a2 + a3 - min(a1, a2, a3)
        scoreB = b1 + b2 + b3 - min(b1, b2, b3)
        if scoreA > scoreB:
            out_lines.append("Alice")
        elif scoreB > scoreA:
            out_lines.append("Bob")
        else:
            out_lines.append("Tie")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    main()

